UPDATE public.questions SET
  stimulus_text = 'The artist wanted to show the reader that the painting was more than just a portrait of a person. To accomplish this, the artist included details in the painting that went beyond the typical conventions of portraiture. The artist did not include any personal details that would identify the subject, and the artist avoided using a traditional pose or setting. Instead, the artist focused on the subject''s inner life, using the painting to communicate a sense of the subject''s character and personality.',
